"""Self-RAG implementation with Claude 4 as both retriever-decider + grader.

Three decisions the model makes:
  1. should_retrieve? -> {yes, no}
  2. for each chunk: is_relevant? -> {relevant, irrelevant}
  3. is_supported? -> {fully, partially, no}
"""
from __future__ import annotations

import os
from dataclasses import dataclass, field

from langchain_anthropic import ChatAnthropic
from langchain_qdrant import QdrantVectorStore
from pydantic import BaseModel, Field

from rag_qdrant_basic import BGEEmbeddings


class RetrieveDecision(BaseModel):
    should_retrieve: bool = Field(description="True if external knowledge is needed.")
    reason: str


class ChunkGrade(BaseModel):
    relevant: bool
    rationale: str


class GroundedAnswer(BaseModel):
    answer: str
    supported: str = Field(description="One of: fully | partially | no")
    citations: list[int] = Field(description="1-indexed chunk numbers used.")


llm = ChatAnthropic(model="claude-sonnet-4-5", temperature=0.2)
store = QdrantVectorStore.from_existing_collection(embedding=BGEEmbeddings(), url=os.environ.get("QDRANT_URL", "http://localhost:6333"), collection_name="ossai_docs")


@dataclass
class SelfRAGResult:
    answer: str
    retrieved: bool
    supported: str
    used_chunks: list[dict] = field(default_factory=list)


def answer_with_self_rag(question: str, top_k: int = 5) -> SelfRAGResult:
    decision = llm.with_structured_output(RetrieveDecision).invoke(
        f"Does answering this question require external knowledge from documents, or can it be answered from general knowledge / casual? Q: {question}"
    )

    if not decision.should_retrieve:
        ans = llm.invoke(f"Answer concisely. Q: {question}")
        return SelfRAGResult(answer=ans.content, retrieved=False, supported="not-applicable")

    candidates = store.similarity_search(question, k=top_k * 2)
    graded: list[dict] = []
    for i, doc in enumerate(candidates):
        grade = llm.with_structured_output(ChunkGrade).invoke(
            f"Question: {question}\nChunk: {doc.page_content[:500]}\n\nIs this chunk relevant to answering the question?"
        )
        if grade.relevant:
            graded.append({"i": i + 1, "content": doc.page_content, "source": doc.metadata.get("source")})
        if len(graded) >= top_k:
            break

    if not graded:
        return SelfRAGResult(answer="I don't have information about that.", retrieved=True, supported="no")

    context = "\n\n".join(f"[{i+1}] {g['content']}" for i, g in enumerate(graded))
    grounded = llm.with_structured_output(GroundedAnswer).invoke(
        f"Answer ONLY from context. Cite [n] for each claim. Be explicit if claims are unsupported.\n\nContext:\n{context}\n\nQuestion: {question}"
    )
    return SelfRAGResult(answer=grounded.answer, retrieved=True, supported=grounded.supported, used_chunks=graded)


if __name__ == "__main__":
    import sys
    q = sys.argv[1] if len(sys.argv) > 1 else "What is our refund policy?"
    r = answer_with_self_rag(q)
    print(r.answer)
    print(f"\n[retrieved={r.retrieved} supported={r.supported}]")

