import { StdioServerTransport } from "@modelcontextprotocol/sdk/server/stdio.js";
import { CallToolRequestSchema, ListToolsRequestSchema } from "@modelcontextprotocol/sdk/types.js";

const TAVILY_KEY = process.env.TAVILY_API_KEY;
const BRAVE_KEY = process.env.BRAVE_API_KEY;
const ALLOWED_DOMAINS = process.env.ALLOWED_DOMAINS?.split(",").map((d) => d.trim()) ?? null;
const cache = new Map<string, { at: number; result: unknown }>();
const TTL_MS = 5 * 60 * 1000;

async function tavily(query: string) {
  if (!TAVILY_KEY) throw new Error("TAVILY_API_KEY not set");
  const r = await fetch("https://api.tavily.com/search", {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({ api_key: TAVILY_KEY, query, search_depth: "basic", max_results: 5, include_answer: true }),
  });
  if (!r.ok) throw new Error(`Tavily ${r.status}: ${await r.text()}`);
  return await r.json();
}

async function brave(query: string) {
  if (!BRAVE_KEY) throw new Error("BRAVE_API_KEY not set");
  const r = await fetch(`https://api.search.brave.com/res/v1/web/search?q=${encodeURIComponent(query)}&count=5`, {
    headers: { "X-Subscription-Token": BRAVE_KEY, Accept: "application/json" },
  });
  if (!r.ok) throw new Error(`Brave ${r.status}: ${await r.text()}`);
  const data: any = await r.json();
  return { results: (data.web?.results ?? []).map((r: any) => ({ title: r.title, url: r.url, content: r.description })), answer: null };
}

function filterDomains(result: any) {
  if (!ALLOWED_DOMAINS) return result;
  result.results = (result.results ?? []).filter((r: any) => {
    try { return ALLOWED_DOMAINS.some((d) => new URL(r.url).hostname.endsWith(d)); }
    catch { return false; }
  });
  return result;
}

const server = new Server({ name: "web-search", version: "1.0.0" }, { capabilities: { tools: {} } });

server.setRequestHandler(ListToolsRequestSchema, async () => ({
  tools: [{ name: "web_search", description: "Search the web. Returns 5 results with title/url/snippet, plus an optional summary.", inputSchema: { type: "object", required: ["query"], properties: { query: { type: "string" } } } }],
}));

server.setRequestHandler(CallToolRequestSchema, async (req) => {
  const query = String(req.params.arguments?.query ?? "").slice(0, 256);
  const cached = cache.get(query);
  if (cached && Date.now() - cached.at < TTL_MS) {
    return { content: [{ type: "text", text: JSON.stringify(cached.result) }] };
  }
  let result;
  try { result = await tavily(query); }
  catch (e) { result = await brave(query).catch((be) => ({ error: `tavily+brave failed: ${(e as Error).message} | ${(be as Error).message}` })); }
  result = filterDomains(result);
  cache.set(query, { at: Date.now(), result });
  return { content: [{ type: "text", text: JSON.stringify(result) }] };
});

await server.connect(new StdioServerTransport());
