"""Tenacity retry chain for LLM calls with 429/Retry-After + circuit breaker."""
from __future__ import annotations

import asyncio
import time
from typing import Any, Callable

import httpx
from tenacity import (
    AsyncRetrying, retry, retry_if_exception_type, retry_if_exception,
    stop_after_attempt, wait_exponential_jitter, wait_fixed, before_sleep_log,
)
import logging

log = logging.getLogger(__name__)


class RateLimited(Exception):
    def __init__(self, retry_after_s: float = 1.0):
        self.retry_after_s = retry_after_s
        super().__init__(f"rate limited, retry in {retry_after_s}s")


def _wait_strategy(retry_state) -> float:
    """If the exception is RateLimited(retry_after_s), wait that. Otherwise exponential jitter."""
    exc = retry_state.outcome.exception() if retry_state.outcome else None
    if isinstance(exc, RateLimited):
        return exc.retry_after_s + 0.5
    return wait_exponential_jitter(initial=1, max=30)(retry_state)


def _should_retry(exc: BaseException) -> bool:
    if isinstance(exc, RateLimited):
        return True
    if isinstance(exc, httpx.HTTPStatusError):
        return exc.response.status_code in (429, 500, 502, 503, 504)
    return isinstance(exc, (httpx.TimeoutException, httpx.NetworkError))


retry_llm = retry(
    retry=retry_if_exception(_should_retry),
    wait=_wait_strategy,
    stop=stop_after_attempt(5),
    before_sleep=before_sleep_log(log, logging.WARNING),
    reraise=True,
)


# --- Circuit breaker (open after N consecutive failures, cool down M seconds) ---
class CircuitBreaker:
    def __init__(self, failure_threshold: int = 5, cooldown_s: int = 30):
        self.threshold = failure_threshold
        self.cooldown_s = cooldown_s
        self.fails = 0
        self.opened_at: float | None = None

    def check(self) -> None:
        if self.opened_at and time.time() - self.opened_at < self.cooldown_s:
            raise RuntimeError(f"circuit open, cool down {self.cooldown_s - (time.time() - self.opened_at):.0f}s")
        if self.opened_at:
            self.opened_at = None
            self.fails = 0

    def record_success(self) -> None:
        self.fails = 0

    def record_failure(self) -> None:
        self.fails += 1
        if self.fails >= self.threshold:
            self.opened_at = time.time()


_breaker = CircuitBreaker()


@retry_llm
async def call_claude(prompt: str) -> str:
    _breaker.check()
    try:
        async with httpx.AsyncClient(timeout=30) as c:
            r = await c.post(
                "https://api.anthropic.com/v1/messages",
                json={"model": "claude-sonnet-4-5", "max_tokens": 500, "messages": [{"role": "user", "content": prompt}]},
                headers={"x-api-key": "sk-ant-...", "anthropic-version": "2023-06-01", "content-type": "application/json"},
            )
            if r.status_code == 429:
                retry_after = float(r.headers.get("retry-after", "1"))
                raise RateLimited(retry_after_s=retry_after)
            r.raise_for_status()
            _breaker.record_success()
            return r.json()["content"][0]["text"]
    except Exception:
        _breaker.record_failure()
        raise


if __name__ == "__main__":
    print(asyncio.run(call_claude("Hello.")))

